const payload = $json.body ?? $json;
const message = String(payload.message ?? '').toLowerCase();
const context = payload.app_context ?? {};
const route = String(context.route ?? '');
const has = (...words) => words.some((word) => message.includes(word));
let selectedSkillId = 'fan.pet_interaction.v1';
let confidence = 0.62;
let reply = '我在，可以陪你一起看今天该做什么。';
let uiActions = [];
if (has('卡片', '回忆', '照片', '生成') || route.includes('memories')) {
  selectedSkillId = 'fan.memory_card_generation.v1';
  confidence = 0.86;
  reply = '可以，我会优先帮你把回忆整理成一张可预览的卡片。';
  uiActions = [{ type: 'navigate', label: '去创造卡片', route: '/memories' }];
} else if (has('任务', '积分', '奖励', '亲密') || route.includes('/pet/task')) {
  selectedSkillId = 'fan.daily_task_planner.v1';
  confidence = 0.84;
  reply = '今天先做最接近完成的任务，再领能马上到账的奖励。';
  uiActions = [{ type: 'navigate', label: '查看今日任务', route: '/pet/task' }];
} else if (has('众筹', '投票', '榜', '排行', '项目', '应援') || route.includes('/crowdfunding')) {
  selectedSkillId = 'fan.star_consulting.v1';
  confidence = 0.82;
  reply = '我会结合票数、项目进度和榜单位置，给你一个不焦虑的应援顺序。';
  uiActions = [{ type: 'navigate', label: '查看众筹', route: '/crowdfunding' }];
} else if (has('审核', '核验', '截图', '金额', '记录')) {
  selectedSkillId = 'fan.record_verify.v1';
  confidence = 0.78;
  reply = '这类内容适合先做一致性检查，低置信度结果会交给人工复核。';
} else if (has('喂', '摸', '玩', '宠物', '陪', 'emo', '小emo')) {
  selectedSkillId = 'fan.pet_interaction.v1';
  confidence = 0.8;
  reply = '小 emo 收到啦，这次互动会转成心情和亲密度变化。';
  uiActions = [{ type: 'navigate', label: '回到宠物页', route: '/pet' }];
}
const skillResult = {
  route,
  current_user_id: context.current_user?.id ?? payload.user_id,
  current_star: context.current_star?.name ?? context.current_user?.current_star_id,
  pet_intimacy: context.pet?.intimacy,
  projects_count: Array.isArray(context.projects) ? context.projects.length : 0,
  tasks_count: Array.isArray(context.tasks) ? context.tasks.length : 0,
  memory_records_count: Array.isArray(context.memory_records) ? context.memory_records.length : 0
};
return [{ json: { skill_id: 'fan.app_agent.v1', status: 'ok', reply, selected_skill_id: selectedSkillId, confidence, skill_result: skillResult, ui_actions: uiActions, state_patches: [], received: payload } }];
